import{_ as e,I as a,c as o,o as l,a4 as p,J as i}from"./chunks/framework.BR-X7tCu.js";const E=JSON.parse('{"title":"如何更换 Neo-MoFox 的端口？","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guides/configuration/how_to_change_port.md","filePath":"docs/guides/configuration/how_to_change_port.md","lastUpdated":1781970535000}'),h={name:"docs/guides/configuration/how_to_change_port.md"};function r(c,s,k,d,g,u){const n=a("NolebaseGitContributors"),t=a("NolebaseGitChangelog");return l(),o("div",null,[s[0]||(s[0]=p(`<h1 id="如何更换-neo-mofox-的端口" tabindex="-1">如何更换 Neo-MoFox 的端口？ <a class="header-anchor" href="#如何更换-neo-mofox-的端口" aria-label="Permalink to “如何更换 Neo-MoFox 的端口？”">​</a></h1><p>在大多数情况下，你<strong>不需要</strong>修改 Neo-MoFox 的默认端口。但如果你遇到了<strong>端口冲突</strong>（例如，电脑上其他程序占用了 <code>8095</code> 端口），那么本指南将帮助你安全地更换端口。</p><p>Neo-MoFox 主要涉及2个端口：</p><ol><li><strong>OneBot 适配器端口</strong> (默认为 <code>8095</code>)：这是 Neo-MoFox 与 Napcat QQ 客户端建立连接的端口。</li><li><strong>HTTP API 端口</strong> (默认为 <code>8000</code>)：这是 Neo-MoFox 的 插件 提供 HTTP API 服务的端口。</li></ol><h2 id="场景1-修改-onebot-适配器端口-例如-8095-端口被占用" tabindex="-1">场景1：修改 OneBot 适配器端口 (例如 <code>8095</code> 端口被占用) <a class="header-anchor" href="#场景1-修改-onebot-适配器端口-例如-8095-端口被占用" aria-label="Permalink to “场景1：修改 OneBot 适配器端口 (例如 8095 端口被占用)”">​</a></h2><p>这个端口是 Neo-MoFox 和 Napcat QQ 客户端之间的“桥梁”。修改它的前提是，你<strong>也需要修改 Napcat QQ 客户端中的反向 WebSocket 端口设置</strong>。</p><p><strong>操作步骤 (共2步)</strong>：</p><h3 id="第一步-修改-napcat-qq-客户端设置" tabindex="-1">第一步：修改 Napcat QQ 客户端设置 <a class="header-anchor" href="#第一步-修改-napcat-qq-客户端设置" aria-label="Permalink to “第一步：修改 Napcat QQ 客户端设置”">​</a></h3><ol><li>打开 Napcat QQ 客户端。</li><li>进入 <code>网络配置</code> 设置。</li><li>找到你添加的反向 WebSocket 设置 (例如 <code>ws://127.0.0.1:8095</code>)。</li><li>将其中的端口号修改为一个新的、未被占用的端口。例如，修改为 <code>9595</code>。</li><li>保存设置。</li></ol><h3 id="第二步-修改-neo-mofox-适配器插件配置" tabindex="-1">第二步：修改 Neo-MoFox 适配器插件配置 <a class="header-anchor" href="#第二步-修改-neo-mofox-适配器插件配置" aria-label="Permalink to “第二步：修改 Neo-MoFox 适配器插件配置”">​</a></h3><ol><li>打开 <code>config/plugins/onebot_adapter/config.toml</code> 文件。</li><li>找到 <code>[onebot_server]</code> 配置节。</li><li>将其中的 <code>port</code> 值修改为<strong>与 Napcat QQ 客户端中设置的新端口完全一致</strong>。</li></ol><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># OneBot WebSocket 服务器配置</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onebot_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ws 连接模式: reverse/direct</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 值类型：str, 默认值：&quot;reverse&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mode = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;reverse&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># OneBot WebSocket 服务地址</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 值类型：str, 默认值：&quot;localhost&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">host = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;localhost&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># OneBot WebSocket 服务端口</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 值类型：int, 默认值：8095</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">port = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9595</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # &lt;-- 确保这里和 Napcat 客户端的新端口一致</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Napcat API 访问令牌（可选）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 值类型：str, 默认值：&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access_token = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span></code></pre></div><p><strong>修改完成后，保存文件，然后按照“先启动 Napcat QQ，再启动 Neo-MoFox”的顺序重启，即可生效。</strong></p><h2 id="场景2-修改-http-api-端口-例如-8000-端口被占用" tabindex="-1">场景2：修改 HTTP API 端口 (例如 <code>8000</code> 端口被占用) <a class="header-anchor" href="#场景2-修改-http-api-端口-例如-8000-端口被占用" aria-label="Permalink to “场景2：修改 HTTP API 端口 (例如 8000 端口被占用)”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">注意</p><p>这个端口是 Neo-MoFox 的 插件 提供 HTTP API 服务的端口。修改它不会影响 Neo-MoFox 与 Napcat QQ 客户端之间的连接。</p></div><p><strong>操作步骤(共1步)</strong>：</p><h3 id="修改-neo-mofox-http-api-配置" tabindex="-1">修改 Neo-MoFox HTTP API 配置 <a class="header-anchor" href="#修改-neo-mofox-http-api-配置" aria-label="Permalink to “修改 Neo-MoFox HTTP API 配置”">​</a></h3><ol><li>打开 <code>config/core.toml</code> 文件。</li><li>找到 <code>[http_router]</code> 配置节。</li><li>将其中的 <code>port</code> 值修改为一个新的、未被占用的端口。例如，修改为 <code>9000</code>。</li></ol><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># HTTP 路由配置节</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 定义 HTTP API 相关的配置参数。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http_router</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 是否启用 HTTP 路由</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 值类型：bool, 默认值：true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable_http_router = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># HTTP 路由监听地址</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 值类型：str, 默认值：&quot;127.0.0.1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http_router_host = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;127.0.0.1&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># HTTP 路由监听端口</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 值类型：int, 默认值：8000</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http_router_port = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # &lt;-- 修改为新的端口，例如 9000</span></span></code></pre></div><p><strong>修改完成后，保存文件，然后重启 Neo-MoFox 即可生效。</strong></p><blockquote><p><strong>💡 总结</strong>:</p><ul><li>修改 <strong>OneBot 连接端口</strong>，需要同时改 <code>Napcat QQ 客户端</code> 和 <code>onebot_adapter</code> 的配置。</li><li>修改 <strong>HTTP API 端口</strong>，只需要改 <code>core.toml</code> 中的 HTTP 路由配置即可。 请根据你的实际情况，选择对应的修改方案。</li></ul></blockquote>`,21)),i(n),i(t)])}const _=e(h,[["render",r]]);export{E as __pageData,_ as default};
